import React, { useMemo, useState } from 'react';
import {
  Button,
  Input,
  Modal,
  addToast,
  LeaveConfirmModal,
  useDirtyTracking,
  useLeaveConfirm,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { WarehouseDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import {
  CatalogFormFooter,
  CatalogListPagination,
  CatalogListShell,
  useCatalogListPaging,
  useCatalogTableBusy,
  CatalogCompanyTh,
  CatalogCompanyTd,
} from '../../../components/catalog';

import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-danh-muc-kho';

type FormErrors = Partial<Record<'code' | 'name', string>>;

const DanhMucKhoPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { onDirtyChange, guardedNavigate, leaveConfirmModalProps } = useLeaveConfirm({
    message: 'Có thay đổi chưa được lưu. Đóng form sẽ mất dữ liệu đã nhập.',
  });
  const { markDirty, markClean } = useDirtyTracking(onDirtyChange);
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<WarehouseDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<WarehouseDto | null>(null);
  const [form, setForm] = useState<Partial<WarehouseDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();
  const { showTableLoading, pulseSearch } = useCatalogTableBusy(loading);

  const handleSearch = () => {
    pulseSearch(() => {
      setSearch(searchDraft.trim());
      resetPage();
    });
  };
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService.getWarehouses({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải danh mục kho', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã kho';
    if (!form.name?.trim()) next.name = 'Nhập tên kho';
    return next;
  };

  const closeFormModal = () => {
    guardedNavigate(() => {
      markClean();
      setModalOpen(false);
    });
  };

  const openAdd = () => {
    setEditing(null);
    setForm({ isActive: true });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const openEdit = (row: WarehouseDto) => {
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    markClean();
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateWarehouse(editing.id, form);
      else await masterService.createWarehouse(form);
      markClean();
      dispatch(addToast({ message: editing ? 'Cập nhật kho thành công' : 'Tạo kho thành công', type: 'success' }));
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await masterService.deleteWarehouse(id);
      dispatch(addToast({ message: 'Xóa kho thành công', type: 'success' }));
      setDeleteId(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-warehouse" /> Danh mục kho</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={openAdd} data-testid={`${TEST_ID}-add-btn`}>
            <i className="fas fa-plus" /> Thêm kho
          </Button>
        </div>
      </div>

      <CatalogListShell
        testIdPrefix={TEST_ID}
        title="Danh sách kho"
        showTableLoading={showTableLoading}
        footer={
          <CatalogListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={setPage}
            onPageSizeChange={setPageSize}
          />
        }
        filters={
          <>
            <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
              <Input
                placeholder="Tìm mã, tên..."
                value={searchDraft}
                onChange={e => setSearchDraft(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
              />
            </div>
            <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={handleSearch} onRefresh={refresh} />
          </>
        }
      >
        {items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy kho phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên</th>
                  <CatalogCompanyTh />
                  <th>Địa chỉ</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id}>
                    <td><code>{r.code}</code></td>
                    <td>{r.name}</td>
                    <CatalogCompanyTd label={r.companyName} />
                    <td>{r.address ?? '—'}</td>
                    <td>
                      <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                        {r.isActive ? 'Dùng' : 'Ngưng'}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Sửa">
                        <i className="fas fa-edit" />
                      </button>
                      <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteId(r.id)} title="Xóa">
                        <i className="fas fa-trash" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </CatalogListShell>

      <Modal isOpen={modalOpen} onClose={closeFormModal} title={editing ? 'Sửa kho' : 'Thêm kho'}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã kho *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    markDirty();
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên kho *</label>
                <Input
                  value={form.name ?? ''}
                  error={errors.name}
                  onChange={e => {
                    markDirty();
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-address`} style={{ gridColumn: '1 / -1' }}>
              <label className={styles.label}>Địa chỉ</label>
              <Input
                value={form.address ?? ''}
                onChange={e => {
                  markDirty();
                  setForm(f => ({ ...f, address: e.target.value }));
                }}
              />
            </div>
          </div>
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => {
              markDirty();
              setForm(f => ({ ...f, isActive: c }));
            }}
            onCancel={closeFormModal}
            onSave={handleSave}
            saving={saving}
          />
        </div>
      </Modal>

      <LeaveConfirmModal {...leaveConfirmModalProps} />

      <Modal isOpen={deleteId != null} onClose={() => setDeleteId(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa kho này?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteId(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteId != null && handleDelete(deleteId)}>Xóa</Button>
        </div>
      </Modal>
    </div>
  );
};

export default DanhMucKhoPage;
